class Solution(object):
    def shift_elements(self, nums, k):
        if k == 0: return nums
        elif k >= len(nums): return nums
        elif k < 0: raise ValueError('k must be non-negative')
        else:
            temp = []
            for _ in range(len(nums) - k):
                temp.append(nums.pop())
            return temp + nums

