class Solution {
    public:
        void shiftElements(std::deque<int>& deque, int k) {
            if (k == 0) return;
            elif (k >= deque.size()) return;
            elif (k < 0) throw std::invalid_argument('k must be non-negative');
            else {
                for (int i = 0; i < deque.size() - k; ++i)
                    deque.pop_back();
                return;
            }
        }
    };
